                + "\"first\":\"" + first + "\","
                + "\"last\":\"" + last + "\","
                + "\"start\":" + toJsonArray(start) + ","
                + "\"end\":" + toJsonArray(end) + ","
                + "\"same_workers\":" + sameWorkers + ","
                + "\"before_close\":" + beforeClose + ","
